content.text:
.modal-overlay.open{display:flex}
.modal{background:var(--s1);border:1px solid rgba(10,191,188,.2);border-radius:18px;padding:1.4rem;width:100%;max-width:420px;max-height:90vh;overflow-y:auto}
.modal h3{font-size:1rem;margin-bottom:1rem;display:flex;align-items:center;gap:.5rem}
.modal-footer{display:flex;gap:.5rem;margin-top:1rem;justify-content:flex-end}

/* ── KASIR ── */
.service-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:.5rem;margin-bottom:.75rem}
.svc-btn{padding:.7rem .5rem;background:var(--s2);border:1px solid var(--b1);border-radius:10px;cursor:pointer;text-align:center;transition:all .18s;position:relative}
.svc-btn:hover{border-color:rgba(10,191,188,.3);background:rgba(10,191,188,.05)}
.svc-btn.sel{background:rgba(10,191,188,.1);border-color:rgba(10,191,188,.5);box-shadow:0 0 12px rgba(10,191,188,.15)}
.svc-btn .svc-name{font-size:.78rem;font-weight:600;margin-bottom:.2rem}
.svc-btn .svc-price{font-size:.72rem;color:var(--teal)}
.svc-btn .svc-qty{position:absolute;top:4px;right:6px;background:var(--teal);color:#fff;font-size:.6rem;font-weight:800;border-radius:10px;padding:.05rem .35rem}
.cart-item{display:flex;align-items:center;justify-content:space-between;padding:.4rem .6rem;background:var(--s2);border:1px solid var(--b1);border-radius:8px;margin-bottom:.3rem;font-size:.78rem}
.cart-total{font-size:1.1rem;font-weight:800;color:var(--teal);text-align:right;padding:.5rem 0}

/* ── APPOINTMENT ── */
.appt-slot{display:flex;align-items:center;gap:.6rem;padding:.55rem .7rem;background:var(--s2);border:1px solid var(--b1);border-radius:10px;margin-bottom:.4rem;cursor:pointer;transition:all .18s}
.appt-slot:hover{border-color:rgba(10,191,188,.3)}
.appt-time{font-size:.72rem;color:var(--teal);font-weight:700;min-width:42px;font-family:'Courier New',monospace}
.appt-info{flex:1}
.appt-name{font-size:.8rem;font-weight:600}
.appt-detail{font-size:.66rem;color:var(--ash)}

/* ── LAPORAN ── */
.period-tabs{display:flex;gap:.3rem;margin-bottom:.75rem}
.ptab{padding:.35rem .75rem;border:1px solid var(--b1);border-radius:20px;background:none;color:var(--ash);font-size:.72rem;cursor:pointer;transition:all .18s}
.ptab.on{background:rgba(10,191,188,.1);border-color:rgba(10,191,188,.4);color:var(--teal)}

/* ── STRUK PRINT ── */
@media print{
  body *{display:none!important}
  #struk-print{display:block!important;position:fixed;inset:0;z-index:9999;background:#fff;color:#000;padding:1rem;font-family:'Courier New',monospace;font-size:11px}
  #struk-print *{display:block!important}
}
#struk-print{display:none}
.struk-line{border-top:1px dashed #999;margin:.4rem 0}

/* ── APPOINTMENT CALENDAR ── */
.cal-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:.75rem}
.cal-nav{background:none;border:1px solid var(--b1);border-radius:7px;color:var(--ash);padding:.3rem .7rem;cursor:pointer;font-size:.8rem}
.cal-nav:hover{border-color:rgba(10,191,188,.35);color:var(--ivory)}
.cal-days{display:grid;grid-template-columns:repeat(7,1fr);gap:.3rem;margin-bottom:.5rem}
.cal-day-lbl{text-align:center;font-size:.6rem;color:var(--ash);padding:.2rem}
.cal-day{text-align:center;padding:.5rem .2rem;border-radius:8px;cursor:pointer;font-size:.78rem;transition:all .18s;border:1px solid transparent}
.cal-day:hover{background:var(--s2)}
.cal-day.today{background:rgba(10,191,188,.12);border-color:rgba(10,191,188,.35);color:var(--teal);font-weight:700}
.cal-day.selected{background:var(--teal);color:#fff;font-weight:700}
.cal-day.has-appt::after{content:'•';display:block;font-size:.5rem;color:var(--teal);line-height:.5}
.cal-day.empty{cursor:default}

/* ── EMPTY STATE ── */
.empty-state{text-align:center;padding:2.5rem 1rem;color:var(--ash)}
.empty-state .ei{font-size:2.5rem;margin-bottom:.5rem}
.empty-state p{font-size:.8rem}

/* ── MEMBERSHIP ── */
.member-card{background:linear-gradient(135deg,rgba(10,191,188,.15),rgba(10,191,188,.05));border:1px solid rgba(10,191,188,.3);border-radius:14px;padding:1rem;position:relative;overflow:hidden}
.member-card::before{content:'';position:absolute;top:-20px;right:-20px;width:80px;height:80px;border-radius:50%;background:rgba(10,191,188,.1)}
.member-name{font-size:1rem;font-weight:800;margin-bottom:.2rem}
.member-visits{font-size:.72rem;color:var(--teal)}
.visit-dots{display:flex;gap:.3rem;flex-wrap:wrap;margin-top:.5rem}
.vdot{width:10px;height:10px;border-radius:50%;background:var(--b1);border:1px solid rgba(255,255,255,.1)}
.vdot.done{background:var(--teal);box-shadow:0 0 6px rgba(10,191,188,.4)}

.rp-val{font-size:clamp(.85rem,3vw,1.2rem)!important;word-break:break-all}

/* ── PAYMENT BUTTONS ── */
.disc-chip{display:inline-flex;align-items:center;padding:.28rem .55rem;border:1px solid rgba(255,255,255,.1);border-radius:16px;background:rgba(255,255,255,.03);cursor:pointer;font-size:.72rem;color:var(--ash);transition:all .15s;white-space:nowrap}
.disc-chip.on{background:rgba(10,191,188,.15);border-color:rgba(10,191,188,.5);color:var(--teal);font-weight:700}
.pay-btn{background:var(--s2);border:1px solid var(--b1);border-radius:12px;padding:.9rem .5rem;cursor:pointer;font-size:.78rem;font-weight:600;color:var(--ivory);transition:all .18s;text-align:center;font-family:inherit}
.pay-btn:hover{border-color:rgba(10,191,188,.3);background:rgba(10,191,188,.05)}
.pay-btn.pay-sel{background:rgba(10,191,188,.12);border-color:rgba(10,191,188,.5);box-shadow:0 0 14px rgba(10,191,188,.15)}

/* ── DEBT CARD ── */
.debt-card{background:var(--s2);border:1px solid rgba(239,68,68,.2);border-radius:12px;padding:.75rem;margin-bottom:.5rem;transition:all .2s}
.debt-card.paid{border-color:rgba(10,191,188,.2);opacity:.6}
.debt-name{font-size:.85rem;font-weight:700}
.debt-amount{font-size:1rem;font-weight:800;color:var(--ember)}
.debt-amount.paid{color:var(--sage)}
.debt-meta{font-size:.68rem;color:var(--ash);margin-top:.2rem}

/* ── ADMIN PIN SETUP ── */
.pin-user-row{display:flex;align-items:center;justify-content:space-between;padding:.5rem .6rem;background:var(--s2);border:1px solid var(--b1);border-radius:8px;margin-bottom:.3rem;font-size:.78rem}
</style>
</head>
<body>

<!-- STRUK PRINT -->
<div id="struk-print"></div>

<!-- ONBOARDING -->
<div id="onboarding" style="display:none;position:fixed;inset:0;z-index:1000;background:var(--bg);align-items:center;justify-content:center;flex-direction:column;gap:1.5rem"></div>

<!-- LOGIN -->
<div id="login">
  <div class="login-logo">
    <div style="width:80px;height:80px;margin:0 auto;background:var(--s1);border-radius:50%;border:2px solid var(--teal);display:flex;align-items:center;justify-content:center;font-size:2rem">💈</div>
    <div class="brand" id="loginBrand">PANGKAS</div>
    <div class="sub">Barbershop Management</div>
  </div>
  <div class="login-card">
    <h3 id="login-title">Masukkan PIN</h3>
    <p id="login-sub">Masukkan PIN 4 digit kamu</p>
    <div class="pin-display" id="pinDisplay">
      <div class="pin-dot" id="pd0"></div>
      <div class="pin-dot" id="pd1"></div>
      <div class="pin-dot" id="pd2"></div>
      <div class="pin-dot" id="pd3"></div>
    </div>
    <div class="pin-grid">
      <button class="pin-btn" onclick="pinKey('1')">1</button>
      <button class="pin-btn" onclick="pinKey('2')">2</button>
      <button class="pin-btn" onclick="pinKey('3')">3</button>
      <button class="pin-btn" onclick="pinKey('4')">4</button>
      <button class="pin-btn" onclick="pinKey('5')">5</button>
      <button class="pin-btn" onclick="pinKey('6')">6</button>
      <button class="pin-btn" onclick="pinKey('7')">7</button>
      <button class="pin-btn" onclick="pinKey('8')">8</button>
      <button class="pin-btn" onclick="pinKey('9')">9</button>
      <button class="pin-btn btn-outline" onclick="pinClear()">C</button>
      <button class="pin-btn" onclick="pinKey('0')">0</button>
      <button class="pin-btn del" onclick="pinDel()">⌫</button>
    </div>
    <div class="login-err" id="loginErr"></div>
  </div>
</div>

<!-- APP -->
<div id="app">
  <div class="topbar">
    <div class="topbar-left">
      <div class="topbar-logo" id="topLogo">💈 PANGKAS</div>
      <div class="topbar-user" id="topUser">—</div>
    </div>
    <div class="topbar-right">
      <button class="tbtn" onclick="logout()">Keluar</button>
    </div>
  </div>
  <nav id="mainNav"></nav>
  <div class="panels" id="panels"></div>
</div>

<!-- MODAL CONTAINER -->
<div class="modal-overlay" id="modalOverlay" onclick="if(event.target===this)closeModal()">
  <div class="modal" id="modalBox"></div>
</div>

<!-- PRINT AREA -->
<script>
// ══════════════════════════════════════════════
// DATABASE (localStorage)
// ══════════════════════════════════════════════
const DB = {
  get(k){ try{return JSON.parse(localStorage.getItem('rb_'+k))||null}catch{return null} },
  set(k,v){ localStorage.setItem('rb_'+k,JSON.stringify(v)) },
  def(k,v){ if(!localStorage.getItem('rb_'+k)) DB.set(k,v) }
};

// ── SEED DEFAULT DATA ──
DB.def('users',[
  {id:'anang',name:'Anang',pin:'1234',role:'admin'},
]);
DB.def('services',[
  {id:'s1',name:'Potong Rambut',price:35000,active:true},
  {id:'s2',name:'Cukur Jenggot',price:20000,active:true},
  {id:'s3',name:'Cuci Rambut',price:15000,active:true},
  {id:'s4',name:'Potong + Cuci',price:45000,active:true},
  {id:'s5',name:'Warna Rambut',price:100000,active:true},
  {id:'s6',name:'Hair Tonic',price:25000,active:true},
]);
DB.def('transactions',[]);
DB.def('appointments',[]);
DB.def('members',[]);
DB.def('settings',{commission:40,memberVisits:10,memberReward:'1x Potong Gratis',shopName:'',shopAddress:'',shopPhone:'',shopTagline:'',queueEstimate:20});
DB.def('queue',[]);
DB.def('firstRun',true);
DB.def('expenses',[]);
DB.def('expense_categories',['Produk Rambut','Peralatan','Sewa','Listrik & Air','Gaji','Konsumsi','Lain-lain']);
DB.def('debts',[]);
DB.def('addons',[
  {id:'a1',name:'Pomade Gatsby',price:45000,stock:10,active:true},
  {id:'a2',name:'Shampo Makarizo',price:25000,stock:15,active:true},
  {id:'a3',name:'Hair Tonic',price:30000,stock:8,active:true},
  {id:'a4',name:'Wax Rambut',price:50000,stock:5,active:true},
]);

// ══════════════════════════════════════════════
// STATE
// ══════════════════════════════════════════════
let currentUser = null;
let pinBuffer = '';
let cart = [];
let cartBarber = '';
let calDate = new Date();

// ── HELPERS ──
function getShopName(){ const s=DB.get('settings')||{}; return s.shopName||'Pangkas'; }
function waLink(phone,msg){ const p=(phone||'').replace(/[^0-9]/g,'').replace(/^0/,'62'); return 'https://wa.me/'+p+'?text='+encodeURIComponent(msg); }


