// ══════════════════════════════════════════════
// ONBOARDING (first run)
// ══════════════════════════════════════════════
function checkFirstRun(){
  const s=DB.get('settings')||{};
  if(DB.get('firstRun')===true && !s.shopName){
    document.getElementById('login').style.display='none';
    document.getElementById('app').style.display='none';
    document.getElementById('onboarding').style.display='flex';
    renderOnboarding();
    return true;
  }
  return false;
}

let obStep=1;
function renderOnboarding(){
  const el=document.getElementById('onboarding');
  const s=DB.get('settings')||{};
  el.innerHTML=`
  <div class="login-logo">
    <div style="width:80px;height:80px;margin:0 auto;background:var(--s1);border-radius:50%;border:2px solid var(--teal);display:flex;align-items:center;justify-content:center;font-size:2rem">💈</div>
    <div class="brand">PANGKAS</div>
    <div class="sub">Setup Awal</div>
  </div>
  <div class="login-card" style="width:340px">
    <div style="display:flex;justify-content:center;gap:.5rem;margin-bottom:1rem">
      <div style="width:10px;height:10px;border-radius:50%;background:${obStep>=1?'var(--teal)':'var(--b1)'}"></div>
      <div style="width:10px;height:10px;border-radius:50%;background:${obStep>=2?'var(--teal)':'var(--b1)'}"></div>
      <div style="width:10px;height:10px;border-radius:50%;background:${obStep>=3?'var(--teal)':'var(--b1)'}"></div>
    </div>
    ${obStep===1?`
      <h3>📍 Info Toko</h3>
      <p style="font-size:.72rem;color:var(--ash);margin-bottom:.8rem">Langkah 1 dari 3</p>
      <div class="field"><label>Nama Toko *</label><input class="finp" id="ob-name" placeholder="Contoh: Rome Bois Barbershop" value="${s.shopName||''}"></div>
      <div class="field"><label>Alamat</label><input class="finp" id="ob-addr" placeholder="Jl. Raya No. 1" value="${s.shopAddress||''}"></div>
      <div class="field"><label>No HP / WhatsApp</label><input class="finp" id="ob-phone" placeholder="08xx-xxxx-xxxx" value="${s.shopPhone||''}"></div>
      <button class="btn btn-teal btn-full" onclick="obNext1()">Lanjut →</button>
    `:''}
    ${obStep===2?`
      <h3>✂️ Layanan</h3>
      <p style="font-size:.72rem;color:var(--ash);margin-bottom:.8rem">Langkah 2 — layanan default sudah disiapkan, bisa diedit nanti di Admin</p>
      <div style="text-align:left">
      ${(DB.get('services')||[]).map(s=>`<div style="display:flex;justify-content:space-between;padding:.3rem 0;font-size:.8rem;border-bottom:1px solid rgba(255,255,255,.04)"><span>${s.name}</span><span style="color:var(--teal)">${rp(s.price)}</span></div>`).join('')}
      </div>
      <div style="display:flex;gap:.5rem;margin-top:1rem">
        <button class="btn btn-outline" onclick="obStep=1;renderOnboarding()">← Kembali</button>
        <button class="btn btn-teal" style="flex:1" onclick="obStep=3;renderOnboarding()">Lanjut →</button>
      </div>
    `:''}
    ${obStep===3?`
      <h3>👤 Admin Pertama</h3>
      <p style="font-size:.72rem;color:var(--ash);margin-bottom:.8rem">Langkah 3 — buat akun admin</p>
      <div class="field"><label>Nama</label><input class="finp" id="ob-admin-name" placeholder="Nama kamu" value="Admin"></div>
      <div class="field"><label>PIN (4 digit)</label><input class="finp" id="ob-admin-pin" type="number" maxlength="4" placeholder="1234"></div>
      <div style="display:flex;gap:.5rem;margin-top:1rem">
        <button class="btn btn-outline" onclick="obStep=2;renderOnboarding()">← Kembali</button>
        <button class="btn btn-teal" style="flex:1" onclick="obFinish()">Mulai Pangkas! 🚀</button>
      </div>
    `:''}
  </div>
  <div style="font-size:.65rem;color:var(--ash);margin-top:1rem">Powered by Pangkas 💈</div>`;
}

function obNext1(){
  const name=document.getElementById('ob-name')?.value?.trim();
  if(!name){alert('Nama toko wajib diisi');return;}
  const s=DB.get('settings')||{};
  s.shopName=name;
  s.shopAddress=document.getElementById('ob-addr')?.value?.trim()||'';
  s.shopPhone=document.getElementById('ob-phone')?.value?.trim()||'';
  DB.set('settings',s);
  obStep=2;renderOnboarding();
}

function obFinish(){
  const name=document.getElementById('ob-admin-name')?.value?.trim()||'Admin';
  const pin=String(document.getElementById('ob-admin-pin')?.value||'').trim();
  if(pin.length!==4){alert('PIN harus 4 digit');return;}
  const users=DB.get('users')||[];
  // Replace default user or add new
  const existing=users.findIndex(u=>u.id==='anang');
  const newUser={id:'admin-'+Date.now(),name,pin,role:'admin'};
  if(existing>=0) users[existing]=newUser; else users.push(newUser);
  DB.set('users',users);
  DB.set('firstRun',false);
  document.getElementById('onboarding').style.display='none';
  document.getElementById('login').style.display='flex';
  // Update login screen brand
  updateLoginBrand();
}

function updateLoginBrand(){
  const el=document.getElementById('loginBrand');
  if(el) el.textContent=getShopName().toUpperCase();
  const logo=document.getElementById('topLogo');
  if(logo) logo.textContent='💈 '+getShopName();
}

// ══════════════════════════════════════════════
// LOGIN
// ══════════════════════════════════════════════
// Check first run on load
if(!checkFirstRun()){
  updateLoginBrand();
}

function pinKey(k){
  if(pinBuffer.length>=4) return;
  pinBuffer+=k;
  updatePinDots();
  if(pinBuffer.length===4) setTimeout(tryLogin,200);
}
function pinDel(){ pinBuffer=pinBuffer.slice(0,-1); updatePinDots(); }
function pinClear(){ pinBuffer=''; updatePinDots(); document.getElementById('loginErr').textContent=''; }
function updatePinDots(){
  for(let i=0;i<4;i++){
    document.getElementById('pd'+i).classList.toggle('filled',i<pinBuffer.length);
  }
}
function tryLogin(){
  const users = DB.get('users')||[];
  const u = users.find(x=>x.pin===pinBuffer);
  if(u){
    currentUser=u;
    document.getElementById('login').style.display='none';
    document.getElementById('app').style.display='flex';
    document.getElementById('topUser').textContent=u.name+(u.role==='admin'?' 👑':'');
    buildNav();
    showTab('home');
  } else {
    document.getElementById('loginErr').textContent='PIN salah, coba lagi';
    pinBuffer='';
    updatePinDots();
    setTimeout(()=>document.getElementById('loginErr').textContent='',2000);
  }
}
function logout(){
  currentUser=null; pinBuffer=''; updatePinDots();
  document.getElementById('app').style.display='none';
  document.getElementById('login').style.display='flex';
}

// ══════════════════════════════════════════════
// NAVIGATION
// ══════════════════════════════════════════════
const TABS_ALL   = [{id:'home',icon:'🏠',label:'Home'},{id:'kasir',icon:'💰',label:'Kasir'},{id:'antrian',icon:'📋',label:'Antrian'},{id:'janji',icon:'📅',label:'Janji'},{id:'member',icon:'👥',label:'Member'},{id:'birthday',icon:'🎂',label:'Ultah'},{id:'laporan',icon:'📊',label:'Laporan'},{id:'hutang',icon:'📒',label:'Hutang'},{id:'belanja',icon:'🛒',label:'Belanja'},{id:'admin',icon:'⚙️',label:'Admin'}];
const TABS_BARBER= [{id:'home',icon:'🏠',label:'Home'},{id:'kasir',icon:'💰',label:'Kasir'},{id:'antrian',icon:'📋',label:'Antrian'},{id:'janji',icon:'📅',label:'Janji'}];

function buildNav(){
  const tabs = currentUser.role==='admin'?TABS_ALL:TABS_BARBER;
  const nav=document.getElementById('mainNav');
  const panels=document.getElementById('panels');
  nav.innerHTML=''; panels.innerHTML='';
  tabs.forEach(t=>{
    const btn=document.createElement('button');
    btn.className='ntab'; btn.id='tab-'+t.id;
    btn.innerHTML=t.icon+' '+t.label;
    btn.onclick=()=>showTab(t.id);
    nav.appendChild(btn);
    const p=document.createElement('div');
    p.className='panel'; p.id='panel-'+t.id;
    panels.appendChild(p);
  });
}

function showTab(id){
  document.querySelectorAll('.ntab').forEach(b=>b.classList.remove('on'));
  document.querySelectorAll('.panel').forEach(p=>p.classList.remove('on'));
  // Always reset cart when switching to kasir
  if(id==='kasir'){ cart=[]; selectedPayMethod=null; }
  const tb=document.getElementById('tab-'+id);
  const pb=document.getElementById('panel-'+id);
  if(tb) tb.classList.add('on');
  if(pb){ pb.classList.add('on'); renderPanel(id); }
}

function renderPanel(id){
  const el=document.getElementById('panel-'+id);
  if(!el) return;
  if(id==='home') renderHome(el);
  else if(id==='kasir') renderKasir(el);
  else if(id==='antrian') renderAntrian(el);
  else if(id==='janji') renderJanji(el);
  else if(id==='member') renderMember(el);
  else if(id==='birthday') renderBirthday(el);
  else if(id==='laporan') renderLaporan(el);
  else if(id==='hutang') renderHutang(el);
  else if(id==='belanja') renderBelanja(el);
  else if(id==='admin') renderAdmin(el);
}

// ══════════════════════════════════════════════
// ══════════════════════════════════════════════
// HOME DASHBOARD
// ══════════════════════════════════════════════
function renderHome(el){
  const txs=DB.get('transactions')||[];
  const now=new Date();
  const todayTx=txs.filter(t=>{const d=new Date(t.date);return d.toDateString()===now.toDateString()});

