  const paidToday=todayTx.filter(t=>!t.isHutang);
  const totalToday=paidToday.reduce((a,t)=>a+t.total,0);
  const queue=DB.get('queue')||[];
  const activeQueue=queue.filter(q=>q.status==='waiting'||q.status==='serving');
  const members=DB.get('members')||[];
  const settings=DB.get('settings')||{};
  const commToday=paidToday.reduce((a,t)=>a+t.commission,0);

  el.innerHTML=`
  <div class="card">
    <div class="card-title">📊 Dashboard — ${now.toLocaleDateString('id-ID',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}</div>
    <div class="grid2" style="margin-bottom:.5rem">
      <div class="stat-card"><div class="stat-val rp-val">${rp(totalToday)}</div><div class="stat-lbl">Pendapatan Hari Ini</div></div>
      <div class="stat-card"><div class="stat-val">${todayTx.length}</div><div class="stat-lbl">Transaksi</div></div>
