function renderCal(){
  const days=['Min','Sen','Sel','Rab','Kam','Jum','Sab'];
  const year=calDate.getFullYear(), month=calDate.getMonth();
  const firstDay=new Date(year,month,1).getDay();
  const daysInMonth=new Date(year,month+1,0).getDate();
  const monthNames=['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  document.getElementById('calMonthLabel').textContent=monthNames[month]+' '+year;
  const appts=DB.get('appointments')||[];
  const grid=document.getElementById('calGrid');
  if(!grid) return;
  // Day labels
  grid.innerHTML='<div class="cal-days">'+days.map(d=>`<div class="cal-day-lbl">${d}</div>`).join('')+'</div>';
  const daysDiv=document.createElement('div');
  daysDiv.className='cal-days';
  // Empty cells
  for(let i=0;i<firstDay;i++){
    const e=document.createElement('div');e.className='cal-day empty';daysDiv.appendChild(e);
  }
  const today=new Date();
  for(let d=1;d<=daysInMonth;d++){
    const dateStr=`${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const hasAppt=appts.some(a=>a.date===dateStr);
    const isToday=today.getDate()===d&&today.getMonth()===month&&today.getFullYear()===year;
    const div=document.createElement('div');
    div.className='cal-day'+(isToday?' today':'')+(hasAppt?' has-appt':'');
    div.textContent=d;
    div.onclick=()=>{ renderApptList(new Date(year,month,d)); };
    daysDiv.appendChild(div);
  }
  grid.appendChild(daysDiv);
}
function calPrev(){ calDate.setMonth(calDate.getMonth()-1); renderCal(); }
function calNext(){ calDate.setMonth(calDate.getMonth()+1); renderCal(); }

