function renderBirthday(el){
  const members=DB.get('members')||[];
  const settings=DB.get('settings')||{};
  const shopName=settings.shopName||'Pangkas';
  const today=new Date();

  // Find birthdays: today + upcoming 7 days
  function getBdayInfo(m){
    if(!m.birthday||!m.phone) return null;
    const bd=new Date(m.birthday);
    const thisYear=new Date(today.getFullYear(),bd.getMonth(),bd.getDate());
    let diff=Math.ceil((thisYear-today)/(1000*60*60*24));
    if(diff<0) diff+=365; // next year
    return {days:diff, bdStr:bd.toLocaleDateString('id-ID',{day:'numeric',month:'long'})};
  }

  const todayBdays=members.filter(m=>{
    if(!m.birthday) return false;
    const bd=new Date(m.birthday);
    return bd.getMonth()===today.getMonth()&&bd.getDate()===today.getDate();
  });

  const upcomingBdays=members.filter(m=>{
    if(!m.birthday) return false;
    const bd=new Date(m.birthday);
    const thisYear=new Date(today.getFullYear(),bd.getMonth(),bd.getDate());
    const diff=Math.ceil((thisYear-today)/(1000*60*60*24));
    return diff>0&&diff<=7;
  }).sort((a,b)=>{
    const bdA=new Date(a.birthday); const bdB=new Date(b.birthday);
    const dA=Math.ceil((new Date(today.getFullYear(),bdA.getMonth(),bdA.getDate())-today)/(1000*60*60*24));
    const dB=Math.ceil((new Date(today.getFullYear(),bdB.getMonth(),bdB.getDate())-today)/(1000*60*60*24));
    return dA-dB;
  });

  const noPhone=members.filter(m=>m.birthday&&!m.phone);

  function waCard(m, isToday){
    const info=getBdayInfo(m);
    const phone=(m.phone||'').replace(/[^0-9]/g,'').replace(/^0/,'62');
    const bdStr=info?info.bdStr:'';
    const daysLabel=isToday?'Hari ini! 🎉':(info?info.days+' hari lagi':'');
    // WA message
    const waText='Halo '+m.name+', Selamat Ulang Tahun ya! Semoga panjang umur, sehat selalu, dan semua harapan terkabul! Spesial buat kamu, ada hadiah istimewa dari kami di '+shopName+'. Dateng ya, kami tunggu! - Tim '+shopName;
    const msg=encodeURIComponent(waText);
    const waUrl='https://wa.me/'+phone+'?text='+msg;
    const cardBg=isToday
      ? 'background:linear-gradient(135deg,rgba(251,191,36,.15),rgba(251,146,60,.08));border:1px solid rgba(251,191,36,.4)'
      : 'background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.08)';
    return '<div style="'+cardBg+';border-radius:14px;padding:.85rem;margin-bottom:.6rem">'+
      '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:.5rem">'+
        '<div>'+
          '<div style="font-weight:700;font-size:.95rem">'+(isToday?'🎂 ':'')+m.name+'</div>'+
          '<div style="font-size:.7rem;color:var(--ash);margin-top:.1rem">'+bdStr+' · '+
            '<span style="color:'+(isToday?'#fbbf24':'var(--teal)')+'">'+daysLabel+'</span>'+
          '</div>'+
          (m.phone?'<div style="font-size:.7rem;color:var(--ash);margin-top:.1rem">📱 '+m.phone+'</div>':'')+ 
        '</div>'+
        (m.phone
          ? '<a href="'+waUrl+'" target="_blank" style="display:inline-flex;align-items:center;gap:.4rem;'+
              'background:'+(isToday?'#25D366':'rgba(37,211,102,.15)')+';'+
              'color:'+(isToday?'#fff':'#25D366')+';'+
              'border:1px solid rgba(37,211,102,.4);border-radius:10px;'+
              'padding:.45rem .85rem;font-size:.78rem;font-weight:700;text-decoration:none;white-space:nowrap">'+
              '<span style="font-size:1rem">💬</span> Kontak Sekarang</a>'
          : '<button class="btn btn-sm btn-outline" onclick="editMember(&#39;'+m.id+'&#39;)">+ Tambah No HP</button>'
        )+
      '</div>'+
    '</div>';
  }

  let html='<div class="card" style="margin-bottom:.6rem">'+
    '<div class="card-title" style="color:#fbbf24">🎂 Ulang Tahun Hari Ini</div>';
  if(todayBdays.length===0){
    html+='<div style="color:var(--ash);font-size:.8rem;padding:.4rem 0">Tidak ada member yang ulang tahun hari ini</div>';
  } else {
    todayBdays.forEach(m=>{ html+=waCard(m,true); });
  }
  html+='</div>';

  if(upcomingBdays.length>0){
    html+='<div class="card" style="margin-bottom:.6rem">'+
      '<div class="card-title">📅 Ulang Tahun 7 Hari ke Depan</div>';
    upcomingBdays.forEach(m=>{ html+=waCard(m,false); });
    html+='</div>';
  }

  if(noPhone.length>0){
    html+='<div class="card">'+
      '<div class="card-title" style="font-size:.8rem;color:var(--ash)">⚠️ Belum Ada No HP ('+noPhone.length+')</div>'+
      '<div style="font-size:.75rem;color:var(--ash);margin-bottom:.5rem">Member ini punya tanggal lahir tapi belum ada nomor WA</div>';
