function setRP(p){ reportPeriod=p; renderLaporan(document.getElementById('panel-laporan')); }

function renderLaporanContent(){
  const el=document.getElementById('laporanContent');
  if(!el) return;
  const txs=DB.get('transactions')||[];
  const now=new Date();
  const filtered=txs.filter(tx=>{
    const d=new Date(tx.date);
    if(reportPeriod==='today') return d.toDateString()===now.toDateString();
    if(reportPeriod==='week'){const w=new Date(now);w.setDate(w.getDate()-7);return d>=w;}
    if(reportPeriod==='month') return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
    return true;
  });
  // Exclude hutang (unpaid) from revenue — only count paid transactions
