function markDebtPaid(id){
  if(!confirm('Tandai hutang ini sebagai LUNAS?')) return;
  const debts=DB.get('debts')||[];
  const d=debts.find(x=>x.id===id);
  if(d){ d.paid=true; d.paidAt=new Date().toISOString(); }
  // Update transaction commission now that it's paid
  if(d){
    const txs=DB.get('transactions')||[];
    const tx=txs.find(t=>t.id===d.txId);
    if(tx){
      const settings=DB.get('settings')||{commission:40};
      tx.commission=Math.round(tx.total*settings.commission/100);
      tx.isHutang=false;
      DB.set('transactions',txs);
    }
  }
  DB.set('debts',debts);
  renderHutang(document.getElementById('panel-hutang'));
}

function deleteDebt(id){
  if(!confirm('Hapus catatan hutang ini?')) return;
  DB.set('debts',(DB.get('debts')||[]).filter(d=>d.id!==id));
  renderHutang(document.getElementById('panel-hutang'));
}

