function renderBelanja(el){
  const expenses=DB.get('expenses')||[];
  const cats=DB.get('expense_categories')||[];
  const now=new Date();
  // Filter this month by default
  const thisMonth=expenses.filter(e=>{
    const d=new Date(e.date);
    return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
  });
  const totalMonth=thisMonth.reduce((a,e)=>a+e.amount,0);
  const totalAll=expenses.reduce((a,e)=>a+e.amount,0);
  // Group by category
  const byCat={};
  thisMonth.forEach(e=>{ byCat[e.category]=(byCat[e.category]||0)+e.amount; });

  el.innerHTML=`
  <div class="grid2" style="margin-bottom:.75rem">
    <div class="stat-card">
      <div class="stat-val" style="font-size:1.1rem;color:var(--ember)">${rp(totalMonth)}</div>
      <div class="stat-lbl">Pengeluaran Bulan Ini</div>
    </div>
    <div class="stat-card">
      <div class="stat-val" style="font-size:1.1rem;color:var(--ember)">${rp(totalAll)}</div>
      <div class="stat-lbl">Total Semua Pengeluaran</div>
    </div>
  </div>

  <div class="card">
    <div class="card-title">Per Kategori (Bulan Ini)</div>
    ${Object.keys(byCat).length===0?'<div style="color:var(--ash);font-size:.78rem;padding:.3rem 0">Belum ada pengeluaran bulan ini</div>':
    Object.entries(byCat).sort((a,b)=>b[1]-a[1]).map(([cat,amt])=>`
    <div style="display:flex;align-items:center;justify-content:space-between;padding:.4rem 0;border-bottom:1px solid rgba(255,255,255,.04);font-size:.78rem">
      <span>📦 ${cat}</span>
      <span style="color:var(--ember);font-weight:700">${rp(amt)}</span>
    </div>`).join('')}
  </div>

  <div class="card">
    <div class="card-title">Riwayat Belanja
      <button class="btn btn-teal btn-sm" onclick="openAddBelanja()">+ Tambah</button>
    </div>
    ${expenses.length===0?'<div class="empty-state"><div class="ei">🛒</div><p>Belum ada catatan pengeluaran</p></div>':''}
    <table class="tbl">
      <thead><tr><th>Tanggal</th><th>Nama</th><th>Kategori</th><th>Jumlah</th><th></th></tr></thead>
      <tbody id="expenseRows">${renderExpenseRows(expenses)}</tbody>
    </table>
  </div>`;
}

function renderExpenseRows(expenses){
  if(expenses.length===0) return '';
  return [...expenses].sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,100).map(function(e){
    const addons=DB.get('addons')||[];
    const linkedAddon=e.addonId?addons.find(a=>a.id===e.addonId):null;
    const qtyLabel=e.qty&&e.qty>1?' ('+e.qty+' pcs @ '+rp(e.unitPrice||0)+')':'';
    const profitHtml=linkedAddon&&e.unitPrice?
      ' <span style="font-size:.62rem;color:var(--sage)">jual '+rp(linkedAddon.price)+' → profit '+rp(linkedAddon.price-(e.unitPrice||0))+'/pcs</span>':'';
    const addonBadge=linkedAddon?'<br><span class="badge badge-teal" style="margin-top:2px">🧴 '+linkedAddon.name+'</span>':'';
    return '<tr>'+
      '<td style="font-size:.7rem;font-family:monospace">'+new Date(e.date).toLocaleDateString('id-ID',{day:'numeric',month:'short'})+'</td>'+
      '<td>'+e.name+qtyLabel+(e.note?'<br><span style="font-size:.62rem;color:var(--ash)">'+e.note+'</span>':'')+addonBadge+profitHtml+'</td>'+
      '<td><span class="badge badge-gray">'+e.category+'</span></td>'+
      '<td style="color:var(--ember);font-weight:600">'+rp(e.amount)+'</td>'+
      '<td style="white-space:nowrap">'+
        '<button onclick="openEditExpense(&#39;'+e.id+'&#39;)" style="background:none;border:1px solid rgba(255,255,255,.1);border-radius:6px;color:var(--ash);cursor:pointer;font-size:.68rem;padding:.15rem .4rem;margin-right:.2rem">Edit</button>'+
        '<button onclick="deleteExpense(&#39;'+e.id+'&#39;)" style="background:none;border:none;color:var(--ember);cursor:pointer;font-size:.9rem">&#128465;</button>'+
      '</td>'+
    '</tr>';
  }).join('');
}

