  const delBtn=document.createElement('button'); delBtn.className='btn btn-danger btn-sm'; delBtn.textContent='Hapus';
  delBtn.onclick=function(){ closeModal(); deleteExpense(id); };
  const cancelBtn=document.createElement('button'); cancelBtn.className='btn btn-outline'; cancelBtn.textContent='Batal'; cancelBtn.onclick=closeModal;
  const saveBtn=document.createElement('button'); saveBtn.className='btn btn-teal'; saveBtn.textContent='Simpan';
  saveBtn.onclick=function(){
    const name=document.getElementById('ee-name')?.value?.trim();
    const cat=document.getElementById('ee-cat')?.value;
    const qty=parseInt(document.getElementById('ee-qty')?.value)||1;
    const unitPrice=parseInt(document.getElementById('ee-unitprice')?.value)||0;
    const amount=parseInt(document.getElementById('ee-amount')?.value)||unitPrice*qty;
    const date=document.getElementById('ee-date')?.value;
    const note=document.getElementById('ee-note')?.value?.trim();
    if(!name||!amount||!date){alert('Nama, jumlah, dan tanggal wajib diisi');return;}
    const exps=DB.get('expenses')||[];
    const ex=exps.find(x=>x.id===id);
    if(ex){ ex.name=name; ex.category=cat; ex.qty=qty; ex.unitPrice=unitPrice; ex.amount=amount; ex.date=date; ex.note=note; }
    DB.set('expenses',exps);
    closeModal();
    renderBelanja(document.getElementById('panel-belanja'));
  };
  footer.appendChild(delBtn); footer.appendChild(cancelBtn); footer.appendChild(saveBtn);
  box.appendChild(footer);
  document.getElementById('modalOverlay').classList.add('open');
}

function selectAddonChip(el){
  // Deselect all
  document.querySelectorAll('.addon-chip').forEach(function(c){
    c.style.background='rgba(255,255,255,.03)';
    c.style.borderColor='rgba(255,255,255,.1)';
    c.style.color='';
    c.querySelector('.chip-dot').style.background='transparent';
    c.querySelector('.chip-dot').style.borderColor='rgba(10,191,188,.4)';
  });
  // Select this
  el.style.background='rgba(10,191,188,.12)';
  el.style.borderColor='rgba(10,191,188,.5)';
  el.querySelector('.chip-dot').style.background='var(--teal)';
  el.querySelector('.chip-dot').style.borderColor='var(--teal)';
  // Set hidden input
  const id=el.getAttribute('data-id')||'';
  const hiddenEl=document.getElementById('ex-addon');
  if(hiddenEl){
    hiddenEl.value=id;
    hiddenEl.dispatchEvent(new Event('change'));
  }
  // Show/hide new addon fields
  const newDiv=document.getElementById('ex-addon-newname');
  if(newDiv) newDiv.style.display=id==='__new__'?'block':'none';
  // Trigger profit update
  const qty=parseInt(document.getElementById('ex-qty')?.value)||1;
  const unitPrice=parseInt(document.getElementById('ex-unitprice')?.value)||0;
  const preview=document.getElementById('ex-profit-preview');
  if(id&&id!=='__new__'&&id!==''){
    const a=(DB.get('addons')||[]).find(x=>x.id===id);
    if(a&&unitPrice>0&&preview){
      const profitPer=a.price-unitPrice;
      const profitTotal=profitPer*qty;
      preview.style.display='block';
      preview.style.background=profitPer>=0?'rgba(16,185,129,.08)':'rgba(239,68,68,.08)';
      preview.style.color=profitPer>=0?'var(--sage)':'var(--ember)';
      preview.style.border='1px solid '+(profitPer>=0?'rgba(16,185,129,.2)':'rgba(239,68,68,.2)');
      preview.textContent='Profit '+rp(profitPer)+'/pcs · Total '+rp(profitTotal)+' ('+qty+' pcs × jual '+rp(a.price)+')';
    } else if(preview) preview.style.display='none';
  } else if(preview) preview.style.display='none';
}

function saveExpense(){
  const name=document.getElementById('ex-name')?.value?.trim();
  let cat=document.getElementById('ex-cat')?.value;
  const qty=parseInt(document.getElementById('ex-qty')?.value)||1;
  const unitPrice=parseInt(document.getElementById('ex-unitprice')?.value)||0;
  const amount=parseInt(document.getElementById('ex-amount')?.value)||unitPrice*qty||0;
  const date=document.getElementById('ex-date')?.value;
  const note=document.getElementById('ex-note')?.value?.trim();
  const addonSel=document.getElementById('ex-addon')?.value||'';
  if(!name||!amount||!date){alert('Nama, jumlah, dan tanggal wajib diisi');return;}
  // Handle new category
  if(cat==='__new__'){
    const newCat=document.getElementById('ex-newcat')?.value?.trim();
    if(!newCat){alert('Masukkan nama kategori baru');return;}
    cat=newCat;
    const cats=DB.get('expense_categories')||[];
    if(!cats.includes(cat)){cats.push(cat);DB.set('expense_categories',cats);}
  }
  const expenses=DB.get('expenses')||[];
  expenses.push({
    id:'ex-'+Date.now(),name,category:cat,
    amount,qty,unitPrice,
    date,note,
    addonId:addonSel&&addonSel!=='__new__'?addonSel:null,
    createdAt:new Date().toISOString()
  });
  DB.set('expenses',expenses);
  // Handle add-on stock update
  if(addonSel&&addonSel!=='__new__'&&addonSel!==''){
    // Add qty to existing addon stock
    const addons=DB.get('addons')||[];
    const a=addons.find(x=>x.id===addonSel);
    if(a){ a.stock=(a.stock||0)+qty; DB.set('addons',addons); }
  } else if(addonSel==='__new__'){
    // Create new addon
    const newName=document.getElementById('ex-addon-name')?.value?.trim()||name;
    const sellPrice=parseInt(document.getElementById('ex-addon-sellprice')?.value)||0;
    if(newName&&sellPrice){
      const addons=DB.get('addons')||[];
      addons.push({id:'a-'+Date.now(),name:newName,price:sellPrice,stock:qty,active:true,hpp:unitPrice});
      DB.set('addons',addons);
    }
  }
  closeModal();
  renderBelanja(document.getElementById('panel-belanja'));
}

function deleteExpense(id){
  if(!confirm('Hapus catatan pengeluaran ini?')) return;
  DB.set('expenses',(DB.get('expenses')||[]).filter(e=>e.id!==id));
  renderBelanja(document.getElementById('panel-belanja'));
}

